    function apply() {
        for (const [topic, levels] of Object.entries(texts)) {
            for (const [levelStr, diffs] of Object.entries(levels)) {
                const level = parseInt(levelStr);
                // Basis-Struktur (topic + level) muss existieren;
                // sehrSchwer wird durch addTexts automatisch angelegt.
                if (!Texts.hasTexts(topic, level, 'leicht')) continue;
                for (const [diff, newTexts] of Object.entries(diffs)) {
                    Texts.addTexts(topic, level, diff, newTexts);
                }
            }
        }
    }

    return { apply };
